import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String fileName = args[0]; // User input for file name

        try {
            Path filePath = Paths.get("C:/files", fileName).normalize(); // Constructing path with base directory and user input
            if (!filePath.startsWith(Paths.get("C:/files").toRealPath())) {
                throw new SecurityException("Access to file outside permitted directory is not allowed.");
            }

            byte[] fileBytes = Files.readAllBytes(filePath); // Reading file content as byte array
            System.out.println(new String(fileBytes)); // Displaying file content as string
        } catch (IOException | SecurityException e) {
            System.out.println("File not found or access denied.");
        }
    }
}

